{
  "name": "pi-review",
  "version": "0.1.0",
  "description": "Pi extension for multi-perspective code review — security, performance, maintainability, testing, production readiness, diff analysis, review quality enforcement",
  "author": "baphuongna",
  "license": "MIT",
  "type": "module",
  "keywords": [
    "pi-package",
    "pi",
    "pi-coding-agent",
    "code-review",
    "review",
    "security",
    "diff"
  ],
  "files": [
    "*.ts",
    "src/**/*.ts",
    "README.md",
    "tsconfig.json"
  ],
  "scripts": {
    "typecheck": "tsc --noEmit",
    "test": "node --experimental-strip-types --test --test-concurrency=1 --test-timeout=30000 test/unit/*.test.ts"
  },
  "exports": {},
  "pi": {
    "extensions": [
      "./index.ts"
    ]
  },
  "peerDependencies": {
    "@mariozechner/pi-agent-core": "*",
    "@mariozechner/pi-ai": "*",
    "@mariozechner/pi-coding-agent": "*"
  },
  "dependencies": {
    "typebox": "^1.1.24"
  },
  "devDependencies": {
    "@mariozechner/pi-coding-agent": "^0.65.0",
    "typescript": "^5.9.3"
  },
  "peerDependenciesMeta": {
    "@mariozechner/pi-agent-core": {
      "optional": true
    },
    "@mariozechner/pi-ai": {
      "optional": true
    },
    "@mariozechner/pi-coding-agent": {
      "optional": true
    }
  }
}

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { registerPiReview } from "./src/extension/register.ts";

export default function (pi: ExtensionAPI): void {
	registerPiReview(pi);
}

import type { ExtensionAPI, ExtensionContext, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { registerReviewTools } from "./tool-registry.ts";

// Import perspectives to trigger registration side effects
import "../perspectives/security.ts";
import "../perspectives/performance.ts";
import "../perspectives/maintainability.ts";
import "../perspectives/style.ts";
import "../perspectives/testing.ts";
import "../perspectives/production.ts";

export function registerPiReview(pi: ExtensionAPI): void {
	pi.on("session_start", (_event, ctx: ExtensionContext) => {
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		// Register review tools
		registerReviewTools(pi);

		// Register slash commands
		registerReviewCommands(pi, ctx);
	});
}

function registerReviewCommands(pi: ExtensionAPI, ctx: ExtensionContext): void {
	// /review — review recent changes
	pi.registerCommand("review", {
		description: "Review code changes. Subcommands: security, performance, diff, report, file <path>",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const arg = args?.trim().toLowerCase() ?? "";
			const { ReviewOrchestrator } = await import("../review/orchestrator.ts");
			const orchestrator = new ReviewOrchestrator(ctx.cwd);
			const { formatReport } = await import("../review/report.ts");

			let output: string;

			if (arg === "security") {
				const report = await orchestrator.reviewDiff(ctx.cwd, { perspectives: ["security"] });
				output = formatReport(report);
			} else if (arg === "performance") {
				const report = await orchestrator.reviewDiff(ctx.cwd, { perspectives: ["performance"] });
				output = formatReport(report);
			} else if (arg === "diff") {
				const report = await orchestrator.reviewDiff(ctx.cwd);
				output = formatReport(report);
			} else if (arg === "report") {
				const diffReport = await orchestrator.reviewDiff(ctx.cwd);
				const report = orchestrator.generateFormattedReport(diffReport.findings, {
					format: "summary",
					groupBy: "severity",
					includeSuggestions: true,
				});
				output = formatReport(report);
			} else if (arg.startsWith("file ")) {
				const file = arg.slice(5).trim();
				if (!file) {
					output = "Usage: /review file <path>";
				} else {
					const report = await orchestrator.reviewFile(ctx.cwd, file, { file });
					output = formatReport(report);
				}
			} else {
				// Default: full review
				const report = await orchestrator.reviewDiff(ctx.cwd);
				output = formatReport(report);
			}

			cmdCtx.ui.notify(output);
		},
	});
}

import type { ExtensionAPI, ToolDefinition } from "@mariozechner/pi-coding-agent";
import { Type } from "typebox";
import { ReviewOrchestrator } from "../review/orchestrator.ts";
import { generateReport, formatReport } from "../review/report.ts";
import { calculateImpact } from "../diff/impact-calculator.ts";
import { classifyChanges, allHunks } from "../diff/change-analysis.ts";

interface ReviewToolResult {
	content: Array<{ type: "text"; text: string }>;
	details: { tool: string; status: "ok" | "error" };
	isError?: boolean;
}

function reviewResult(text: string, isError = false): ReviewToolResult {
	return {
		content: [{ type: "text", text }],
		details: { tool: "pi-review", status: isError ? "error" : "ok" },
		...(isError ? { isError: true as const } : {}),
	};
}

export function registerReviewTools(pi: ExtensionAPI): void {
	// review_diff
	pi.registerTool({
		name: "review_diff",
		label: "Review Diff",
		description: "Review git diff with multi-perspective analysis. Returns findings categorized by security, performance, maintainability, testing, and production readiness.",
		parameters: Type.Object({
			base: Type.Optional(Type.String({ description: "Git base ref (default: HEAD~1 or main)." })),
			head: Type.Optional(Type.String({ description: "Git head ref (default: HEAD)." })),
			perspectives: Type.Optional(Type.Array(Type.String(), { description: "Review perspectives to use. Default: all enabled." })),
			maxFiles: Type.Optional(Type.Number({ description: "Maximum files to review. Default: 20." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, ctx) {
			const p = params as { base?: string; head?: string; perspectives?: string[]; maxFiles?: number };
			try {
				const orchestrator = new ReviewOrchestrator(ctx.cwd);
				const report = await orchestrator.reviewDiff(ctx.cwd, {
					base: p.base,
					head: p.head,
					perspectives: p.perspectives,
					maxFiles: p.maxFiles,
				});
				const formatted = formatReport(report);
				return reviewResult(formatted);
			} catch (error) {
				return reviewResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// review_file
	pi.registerTool({
		name: "review_file",
		label: "Review File",
		description: "Review a single file with multi-perspective analysis. Use 'full' context for complete file review or 'changed-only' for diff-based review.",
		parameters: Type.Object({
			file: Type.String({ description: "File path to review." }),
			perspectives: Type.Optional(Type.Array(Type.String(), { description: "Review perspectives to use." })),
			context: Type.Optional(Type.String({ description: "'full' for complete file or 'changed-only' for diff. Default: full." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, ctx) {
			const p = params as { file: string; perspectives?: string[]; context?: string };
			try {
				const orchestrator = new ReviewOrchestrator(ctx.cwd);
				const report = await orchestrator.reviewFile(ctx.cwd, p.file, {
					file: p.file,
					perspectives: p.perspectives,
					context: p.context === "changed-only" ? "changed-only" : "full",
				});
				const formatted = formatReport(report);
				return reviewResult(formatted);
			} catch (error) {
				return reviewResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// review_report
	pi.registerTool({
		name: "review_report",
		label: "Review Report",
		description: "Generate a formatted review report from findings. Supports markdown, JSON, and summary formats.",
		parameters: Type.Object({
			format: Type.Optional(Type.String({ description: "Output format: 'markdown', 'json', or 'summary'. Default: markdown." })),
			includeSuggestions: Type.Optional(Type.Boolean({ description: "Include fix suggestions. Default: true." })),
			groupBy: Type.Optional(Type.String({ description: "Group findings by: 'file', 'perspective', or 'severity'. Default: file." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, ctx) {
			const p = params as { format?: string; includeSuggestions?: boolean; groupBy?: string };
			try {
				const orchestrator = new ReviewOrchestrator(ctx.cwd);

				// Run a diff review first to get current findings
				const diffReport = await orchestrator.reviewDiff(ctx.cwd);
				const report = orchestrator.generateFormattedReport(
					diffReport.findings,
					{
						format: (p.format === "json" ? "json" : p.format === "summary" ? "summary" : "markdown") as "markdown" | "json" | "summary",
						groupBy: (p.groupBy === "perspective" ? "perspective" : p.groupBy === "severity" ? "severity" : "file") as "file" | "perspective" | "severity",
						includeSuggestions: p.includeSuggestions !== false,
					},
				);
				const formatted = formatReport(report);
				return reviewResult(formatted);
			} catch (error) {
				return reviewResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);
}

import * as fs from "node:fs";
import * as path from "node:path";
import type { ReviewExtensionConfig, PerspectiveConfig, QualityConfig, AutoReviewConfig, Severity } from "./types.ts";

const DEFAULT_PERSPECTIVE_SEVERITY: Record<string, Severity> = {
	security: "must-fix",
	performance: "should-fix",
	maintainability: "should-fix",
	style: "nice-to-have",
	testing: "should-fix",
	production: "should-fix",
};

function defaultPerspectives(): Record<string, PerspectiveConfig> {
	const entries = Object.entries(DEFAULT_PERSPECTIVE_SEVERITY);
	const result: Record<string, PerspectiveConfig> = {};
	for (const [name, severity] of entries) {
		result[name] = { enabled: name !== "production", severity };
	}
	return result;
}

const DEFAULT_QUALITY: QualityConfig = {
	rejectGeneric: true,
	requireEvidence: true,
	minFindingsPerFile: 1,
};

const DEFAULT_AUTO_REVIEW: AutoReviewConfig = {
	onEdit: false,
	onCommit: true,
	onPR: true,
};

export const DEFAULT_CONFIG: ReviewExtensionConfig = {
	enabled: true,
	perspectives: defaultPerspectives(),
	quality: { ...DEFAULT_QUALITY },
	autoReview: { ...DEFAULT_AUTO_REVIEW },
};

export function loadConfig(cwd: string): { config: ReviewExtensionConfig; source: "file" | "defaults" } {
	const configPath = path.join(cwd, ".pi", "pi-review.json");

	if (!fs.existsSync(configPath)) {
		return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
	}

	try {
		const raw = fs.readFileSync(configPath, "utf-8");
		const parsed: unknown = JSON.parse(raw);

		if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
			return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
		}

		const user = parsed as Record<string, unknown>;
		const config = structuredClone(DEFAULT_CONFIG);

		if (typeof user.enabled === "boolean") {
			config.enabled = user.enabled;
		}

		if (typeof user.perspectives === "object" && user.perspectives !== null && !Array.isArray(user.perspectives)) {
			const perspectives = user.perspectives as Record<string, unknown>;
			for (const [name, value] of Object.entries(perspectives)) {
				if (typeof value === "object" && value !== null && !Array.isArray(value)) {
					const p = value as Record<string, unknown>;
					config.perspectives[name] = {
						enabled: typeof p.enabled === "boolean" ? p.enabled : true,
						severity: typeof p.severity === "string" ? (p.severity as Severity) : DEFAULT_PERSPECTIVE_SEVERITY[name] ?? "should-fix",
					};
				}
			}
		}

		if (typeof user.quality === "object" && user.quality !== null && !Array.isArray(user.quality)) {
			const q = user.quality as Record<string, unknown>;
			if (typeof q.rejectGeneric === "boolean") config.quality.rejectGeneric = q.rejectGeneric;
			if (typeof q.requireEvidence === "boolean") config.quality.requireEvidence = q.requireEvidence;
			if (typeof q.minFindingsPerFile === "number") config.quality.minFindingsPerFile = q.minFindingsPerFile;
		}

		if (typeof user.autoReview === "object" && user.autoReview !== null && !Array.isArray(user.autoReview)) {
			const a = user.autoReview as Record<string, unknown>;
			if (typeof a.onEdit === "boolean") config.autoReview.onEdit = a.onEdit;
			if (typeof a.onCommit === "boolean") config.autoReview.onCommit = a.onCommit;
			if (typeof a.onPR === "boolean") config.autoReview.onPR = a.onPR;
		}

		return { config, source: "file" };
	} catch {
		return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
	}
}

