import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { registerPiVisual } from "./src/extension/register.ts";

export default function (pi: ExtensionAPI): void {
	registerPiVisual(pi);
}

import * as fs from "node:fs";
import * as path from "node:path";

export interface AutoOpenConfig {
	planReview: boolean;
	diffReview: boolean;
	progressWidget: boolean;
}

export interface VisualConfig {
	enabled: boolean;
	autoOpen: AutoOpenConfig;
	diffViewer: "tui" | "text";
	syntaxHighlighting: boolean;
	maxDiffLines: number;
}

export const DEFAULT_CONFIG: VisualConfig = {
	enabled: true,
	autoOpen: {
		planReview: true,
		diffReview: false,
		progressWidget: true,
	},
	diffViewer: "tui",
	syntaxHighlighting: true,
	maxDiffLines: 500,
};

export function loadConfig(cwd: string): { config: VisualConfig; source: "file" | "defaults" } {
	const configPath = path.join(cwd, ".pi", "pi-visual.json");

	if (!fs.existsSync(configPath)) {
		return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
	}

	try {
		const raw = fs.readFileSync(configPath, "utf-8");
		const parsed: unknown = JSON.parse(raw);

		if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
			return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
		}

		const user = parsed as Record<string, unknown>;
		const config = structuredClone(DEFAULT_CONFIG);

		if (typeof user.enabled === "boolean") {
			config.enabled = user.enabled;
		}

		if (typeof user.autoOpen === "object" && user.autoOpen !== null && !Array.isArray(user.autoOpen)) {
			const ao = user.autoOpen as Record<string, unknown>;
			if (typeof ao.planReview === "boolean") config.autoOpen.planReview = ao.planReview;
			if (typeof ao.diffReview === "boolean") config.autoOpen.diffReview = ao.diffReview;
			if (typeof ao.progressWidget === "boolean") config.autoOpen.progressWidget = ao.progressWidget;
		}

		if (typeof user.diffViewer === "string" && (user.diffViewer === "tui" || user.diffViewer === "text")) {
			config.diffViewer = user.diffViewer;
		}

		if (typeof user.syntaxHighlighting === "boolean") {
			config.syntaxHighlighting = user.syntaxHighlighting;
		}

		if (typeof user.maxDiffLines === "number" && user.maxDiffLines > 0) {
			config.maxDiffLines = user.maxDiffLines;
		}

		return { config, source: "file" };
	} catch {
		return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
	}
}

import type { ExtensionAPI, ToolDefinition } from "@mariozechner/pi-coding-agent";
import { Type } from "typebox";

interface ToolResult {
	content: Array<{ type: "text"; text: string }>;
	details: { tool: string; status: "ok" | "error" };
	isError?: boolean;
}

function result(text: string, isError = false): ToolResult {
	return {
		content: [{ type: "text", text }],
		details: { tool: "pi-visual", status: isError ? "error" : "ok" },
		...(isError ? { isError: true as const } : {}),
	};
}

/** Mutable state shared between tools and overlays. */
export interface VisualState {
	plan: PlanState | null;
	progress: ProgressState | null;
	findings: FindingEntry[];
}

export interface PlanTask {
	id: string;
	description: string;
	files: string[];
	complexity?: string;
	dependsOn?: string[];
	status: "pending" | "in-progress" | "done";
}

export interface PlanState {
	title: string;
	status: "DRAFT" | "READY" | "APPROVED" | "REJECTED";
	tasks: PlanTask[];
}

export interface ProgressState {
	total: number;
	completed: number;
	currentTask: string;
	phase: string;
	cost?: number;
}

export interface FindingEntry {
	file: string;
	line?: number;
	severity: "critical" | "high" | "medium" | "low";
	message: string;
}

export function createVisualState(): VisualState {
	return { plan: null, progress: null, findings: [] };
}

export function registerVisualTools(pi: ExtensionAPI, state: VisualState): void {
	// visual_update_plan
	pi.registerTool({
		name: "visual_update_plan",
		label: "Update Visual Plan",
		description: "Push plan state to pi-visual for display in the plan review overlay. Called by pi-pipeline or pi-crew when plan state changes.",
		parameters: Type.Object({
			title: Type.String({ description: "Plan title." }),
			status: Type.String({ description: "Plan status: DRAFT, READY, APPROVED, REJECTED." }),
			tasks: Type.Array(
				Type.Object({
					id: Type.String({ description: "Task ID." }),
					description: Type.String({ description: "Task description." }),
					files: Type.Array(Type.String(), { description: "Files affected." }),
					complexity: Type.Optional(Type.String({ description: "Complexity level." })),
					dependsOn: Type.Optional(Type.Array(Type.String(), { description: "Task IDs this depends on." })),
					status: Type.String({ description: "Task status: pending, in-progress, done." }),
				}),
				{ description: "Plan tasks." },
			),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { title: string; status: string; tasks: PlanTask[] };
			const validStatuses = ["DRAFT", "READY", "APPROVED", "REJECTED"];
			if (!validStatuses.includes(p.status)) {
				return result(`Invalid plan status: ${p.status}. Must be one of: ${validStatuses.join(", ")}`, true);
			}
			const validTaskStatuses = ["pending", "in-progress", "done"];
			for (const task of p.tasks) {
				if (!validTaskStatuses.includes(task.status)) {
					return result(`Invalid task status: ${task.status} for task ${task.id}`, true);
				}
			}
			state.plan = {
				title: p.title,
				status: p.status as PlanState["status"],
				tasks: p.tasks.map((t) => ({
					...t,
					status: t.status as PlanTask["status"],
				})),
			};
			return result(`Plan updated: "${p.title}" with ${p.tasks.length} tasks (${p.status})`);
		},
	} satisfies ToolDefinition);

	// visual_update_progress
	pi.registerTool({
		name: "visual_update_progress",
		label: "Update Visual Progress",
		description: "Push progress state to pi-visual for the task progress widget. Called by pi-crew when task status changes.",
		parameters: Type.Object({
			total: Type.Number({ description: "Total number of tasks." }),
			completed: Type.Number({ description: "Number of completed tasks." }),
			currentTask: Type.String({ description: "Name of current task." }),
			phase: Type.String({ description: "Current phase (e.g., exploring, planning, executing, reviewing)." }),
			cost: Type.Optional(Type.Number({ description: "Running cost in USD." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { total: number; completed: number; currentTask: string; phase: string; cost?: number };
			if (p.total < 0 || p.completed < 0 || p.completed > p.total) {
				return result("Invalid progress: completed must be 0..total and total >= 0", true);
			}
			state.progress = {
				total: p.total,
				completed: p.completed,
				currentTask: p.currentTask,
				phase: p.phase,
				cost: p.cost,
			};
			return result(`Progress updated: ${p.completed}/${p.total} — ${p.currentTask} (${p.phase})`);
		},
	} satisfies ToolDefinition);

	// visual_show_findings
	pi.registerTool({
		name: "visual_show_findings",
		label: "Show Visual Findings",
		description: "Push review findings to pi-visual for the diff review overlay. Called by pi-review when review completes.",
		parameters: Type.Object({
			findings: Type.Array(
				Type.Object({
					file: Type.String({ description: "File path." }),
					line: Type.Optional(Type.Number({ description: "Line number." })),
					severity: Type.String({ description: "Severity: critical, high, medium, low." }),
					message: Type.String({ description: "Finding message." }),
				}),
				{ description: "Review findings." },
			),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { findings: FindingEntry[] };
			const validSeverities = ["critical", "high", "medium", "low"];
			for (const f of p.findings) {
				if (!validSeverities.includes(f.severity)) {
					return result(`Invalid severity: ${f.severity}`, true);
				}
			}
			state.findings = p.findings;
			return result(`Received ${p.findings.length} findings`);
		},
	} satisfies ToolDefinition);
}

import type { ExtensionAPI, ExtensionContext, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { registerVisualTools, createVisualState, type VisualState } from "./tool-registry.ts";

let sharedState: VisualState = createVisualState();

export function getSharedState(): VisualState {
	return sharedState;
}

export function registerPiVisual(pi: ExtensionAPI): void {
	pi.on("session_start", (_event, ctx: ExtensionContext) => {
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		// Reset state for new session
		sharedState = createVisualState();

		// Register visual tools
		registerVisualTools(pi, sharedState);

		// Register slash commands
		registerVisualCommands(pi, ctx, sharedState);
	});
}

function registerVisualCommands(pi: ExtensionAPI, _ctx: ExtensionContext, state: VisualState): void {
	pi.registerCommand("visual", {
		description: "Visual overlays. Subcommands: plan, diff, architecture, progress",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const subcommand = args?.trim().toLowerCase().split(/\s+/)[0] ?? "";

			switch (subcommand) {
				case "plan": {
					const { PlanOverlay } = await import("../plan/plan-overlay.ts");
					const overlay = new PlanOverlay(state);
					const lines = overlay.render(80);
					cmdCtx.ui.notify(lines.join("\n"));
					break;
				}
				case "diff": {
					const { DiffOverlay } = await import("../diff/diff-overlay.ts");
					const overlay = new DiffOverlay(state);
					const lines = overlay.render(80);
					cmdCtx.ui.notify(lines.join("\n"));
					break;
				}
				case "architecture": {
					const { ArchOverlay } = await import("../architecture/arch-overlay.ts");
					const overlay = new ArchOverlay(state);
					const lines = overlay.render(80);
					cmdCtx.ui.notify(lines.join("\n"));
					break;
				}
				case "progress": {
					const { ProgressWidget } = await import("../progress/progress-widget.ts");
					const widget = new ProgressWidget(state);
					const lines = widget.render(80);
					cmdCtx.ui.notify(lines.join("\n"));
					break;
				}
				default:
					cmdCtx.ui.notify(
						"Usage: /visual <plan|diff|architecture|progress>\n" +
						"  plan        — Open plan review overlay\n" +
						"  diff        — Open diff review overlay\n" +
						"  architecture — Open architecture view\n" +
						"  progress    — Show task progress widget",
					);
			}
		},
	});
}

/** TUI Component interface matching Pi's component model. */
export interface Component {
	render(width: number): string[];
	handleInput?(data: string): void;
	dispose?(): void;
}

/** Scrollable container that wraps a child component in a virtual-scroll viewport. */
export class Scrollable implements Component {
	private scrollOffset = 0;
	private cachedLines: string[] = [];

	constructor(
		private child: Component,
		private maxHeight: number = 20,
	) {}

	getScrollOffset(): number {
		return this.scrollOffset;
	}

	setScrollOffset(offset: number): void {
		this.scrollOffset = Math.max(0, offset);
	}

	getMaxHeight(): number {
		return this.maxHeight;
	}

	setMaxHeight(h: number): void {
		this.maxHeight = h;
	}

	render(width: number): string[] {
		this.cachedLines = this.child.render(width);
		const visible = this.cachedLines.slice(this.scrollOffset, this.scrollOffset + this.maxHeight);

		// If not enough lines to fill viewport, scroll up
		if (visible.length < this.maxHeight && this.scrollOffset > 0) {
			this.scrollOffset = Math.max(0, this.cachedLines.length - this.maxHeight);
			return this.cachedLines.slice(this.scrollOffset, this.scrollOffset + this.maxHeight);
		}

		return visible;
	}

	handleInput(data: string): void {
		const total = this.cachedLines.length;
		switch (data) {
			case "\x1b[A": // Up arrow
			case "k":
				this.scrollOffset = Math.max(0, this.scrollOffset - 1);
				break;
			case "\x1b[B": // Down arrow
			case "j":
				this.scrollOffset = Math.min(Math.max(0, total - this.maxHeight), this.scrollOffset + 1);
				break;
			case "\x1b[5~": // Page Up
				this.scrollOffset = Math.max(0, this.scrollOffset - this.maxHeight);
				break;
			case "\x1b[6~": // Page Down
				this.scrollOffset = Math.min(Math.max(0, total - this.maxHeight), this.scrollOffset + this.maxHeight);
				break;
			case "g": // Home
				this.scrollOffset = 0;
				break;
			case "G": // End
				this.scrollOffset = Math.max(0, total - this.maxHeight);
				break;
		}
	}

	getTotalLines(): number {
		return this.cachedLines.length;
	}
}

import { Scrollable, type Component } from "./scrollable.ts";

export interface SelectableItem {
	label: string;
	description?: string;
	data?: unknown;
}

export class SelectableList implements Component {
	private scrollable: Scrollable;
	private selectedIndex = 0;
	private items: SelectableItem[];
	private onSelect?: (item: SelectableItem, index: number) => void;

	constructor(
		items: SelectableItem[],
		opts?: {
			maxHeight?: number;
			onSelect?: (item: SelectableItem, index: number) => void;
		},
	) {
		this.items = items;
		this.onSelect = opts?.onSelect;
		// Inner component for rendering raw list
		const inner: Component = {
			render: (width: number) => this.renderItems(width),
		};
		this.scrollable = new Scrollable(inner, opts?.maxHeight ?? 15);
	}

	getSelectedIndex(): number {
		return this.selectedIndex;
	}

	setItems(items: SelectableItem[]): void {
		this.items = items;
		if (this.selectedIndex >= items.length) {
			this.selectedIndex = Math.max(0, items.length - 1);
		}
	}

	render(width: number): string[] {
		return this.scrollable.render(width);
	}

	handleInput(data: string): void {
		switch (data) {
			case "\x1b[A": // Up arrow
			case "k":
				if (this.selectedIndex > 0) {
					this.selectedIndex--;
					this.ensureVisible();
				}
				break;
			case "\x1b[B": // Down arrow
			case "j":
				if (this.selectedIndex < this.items.length - 1) {
					this.selectedIndex++;
					this.ensureVisible();
				}
				break;
			case "\r": // Enter
			case " ":
				if (this.onSelect && this.items[this.selectedIndex]) {
					this.onSelect(this.items[this.selectedIndex], this.selectedIndex);
				}
				break;
			default:
				this.scrollable.handleInput(data);
				break;
		}
	}

	private ensureVisible(): void {
		const offset = this.scrollable.getScrollOffset();
		const max = this.scrollable.getMaxHeight();
		if (this.selectedIndex < offset) {
			this.scrollable.setScrollOffset(this.selectedIndex);
		} else if (this.selectedIndex >= offset + max) {
			this.scrollable.setScrollOffset(this.selectedIndex - max + 1);
		}
	}

	private renderItems(width: number): string[] {
		return this.items.map((item, i) => {
			const marker = i === this.selectedIndex ? " > " : "   ";
			const label = item.label;
			const line = `${marker}${label}`;
			if (line.length > width) {
				return line.slice(0, width);
			}
			return line;
		});
	}
}

import type { Component } from "./scrollable.ts";

export type SplitDirection = "horizontal" | "vertical";

export class SplitPane implements Component {
	constructor(
		private left: Component,
		private right: Component,
		private direction: SplitDirection = "horizontal",
		private splitRatio: number = 0.5,
	) {}

	setSplitRatio(ratio: number): void {
		this.splitRatio = Math.max(0.1, Math.min(0.9, ratio));
	}

	render(width: number): string[] {
		if (this.direction === "horizontal") {
			return this.renderSideBySide(width);
		}
		return this.renderStacked(width);
	}

	handleInput(data: string): void {
		// Pass input to both children; the focused one should handle it
		this.left.handleInput?.(data);
		this.right.handleInput?.(data);
	}

	private renderSideBySide(width: number): string[] {
		const dividerWidth = 1;
		const leftWidth = Math.max(1, Math.floor((width - dividerWidth) * this.splitRatio));
		const rightWidth = Math.max(1, width - leftWidth - dividerWidth);

		const leftLines = this.left.render(leftWidth);
		const rightLines = this.right.render(rightWidth);

		const maxLines = Math.max(leftLines.length, rightLines.length);
		const result: string[] = [];

		for (let i = 0; i < maxLines; i++) {
			const left = (leftLines[i] ?? "").padEnd(leftWidth).slice(0, leftWidth);
			const right = (rightLines[i] ?? "").padEnd(rightWidth).slice(0, rightWidth);
			result.push(`${left}│${right}`);
		}

		return result;
	}

	private renderStacked(width: number): string[] {
		const leftLines = this.left.render(width);
		const divider = "─".repeat(width);
		const rightLines = this.right.render(width);
		return [...leftLines, divider, ...rightLines];
	}
}

/** Lightweight markdown-to-ANSI renderer for TUI components. */

export interface MarkupTheme {
	heading: (text: string) => string;
	bold: (text: string) => string;
	dim: (text: string) => string;
	code: (text: string) => string;
	bullet: (text: string) => string;
	hr: string;
}

/** Default ANSI theme using escape codes. */
export const ANSI_THEME: MarkupTheme = {
	heading: (t) => `\x1b[1;4m${t}\x1b[0m`,
	bold: (t) => `\x1b[1m${t}\x1b[0m`,
	dim: (t) => `\x1b[2m${t}\x1b[0m`,
	code: (t) => `\x1b[36m${t}\x1b[0m`,
	bullet: (t) => `  • ${t}`,
	hr: "─".repeat(60),
};

/** Plain text theme (no ANSI escapes). */
export const PLAIN_THEME: MarkupTheme = {
	heading: (t) => t,
	bold: (t) => t,
	dim: (t) => t,
	code: (t) => t,
	bullet: (t) => `  • ${t}`,
	hr: "─".repeat(60),
};

/** Render a simple markdown string into styled string lines. */
export function renderMarkup(markdown: string, theme: MarkupTheme = PLAIN_THEME): string[] {
	const lines = markdown.split("\n");
	const result: string[] = [];

	let inCodeBlock = false;
	for (const line of lines) {
		if (line.startsWith("```")) {
			inCodeBlock = !inCodeBlock;
			continue;
		}
		if (inCodeBlock) {
			result.push(theme.dim(`    ${line}`));
			continue;
		}
		if (line.startsWith("### ")) {
			result.push(theme.heading(line.slice(4)));
		} else if (line.startsWith("## ")) {
			result.push(theme.heading(line.slice(3)));
		} else if (line.startsWith("# ")) {
			result.push(theme.heading(line.slice(2)));
		} else if (line.startsWith("---")) {
			result.push(theme.hr);
		} else if (line.startsWith("- ") || line.startsWith("* ")) {
			const content = applyInline(line.slice(2), theme);
			result.push(theme.bullet(content));
		} else if (line.trim() === "") {
			result.push("");
		} else {
			result.push(applyInline(line, theme));
		}
	}

	return result;
}

/** Apply inline formatting: **bold**, `code`. */
function applyInline(text: string, theme: MarkupTheme): string {
	// Bold: **text**
	let result = text.replace(/\*\*(.+?)\*\*/g, (_, content: string) => theme.bold(content));
	// Code: `text`
	result = result.replace(/`(.+?)`/g, (_, content: string) => theme.code(content));
	return result;
}

import type { Component } from "../components/scrollable.ts";
import type { ProgressState } from "../extension/tool-registry.ts";

/** Single-line progress bar component. */
export class StatusLine implements Component {
	constructor(private state: ProgressState) {}

	update(state: ProgressState): void {
		this.state = state;
	}

	render(width: number): string[] {
		const { total, completed, currentTask, phase, cost } = this.state;

		const pct = total > 0 ? completed / total : 0;
		const barWidth = 20;
		const filled = Math.round(barWidth * pct);
		const empty = barWidth - filled;
		const bar = "█".repeat(filled) + "░".repeat(empty);
		const pctStr = `${Math.round(pct * 100)}%`;

		let line = `📊 Pipeline: [${bar}] ${pctStr} — ${completed}/${total} (${phase}: ${currentTask})`;
		if (cost !== undefined) {
			line += ` | Cost: $${cost.toFixed(2)}`;
		}

		if (line.length > width) {
			line = line.slice(0, width);
		}

		return [line];
	}
}

