/** Renders a single task card within the plan review overlay. */
export class TaskCard implements Component {
	constructor(private task: PlanTask) {}

	getTask(): PlanTask {
		return this.task;
	}

	update(task: PlanTask): void {
		this.task = task;
	}

	render(width: number): string[] {
		const { id, description, files, complexity, dependsOn, status } = this.task;

		const check = status === "done" ? "[✓]" : status === "in-progress" ? "[→]" : "[ ]";
		const header = `${check} ${id}. ${description}`;

		const lines: string[] = [];
		lines.push(truncate(header, width));

		if (files.length > 0) {
			const filesStr = `    Files: ${files.join(", ")}`;
			lines.push(truncate(filesStr, width));
		}

		if (complexity) {
			lines.push(truncate(`    Complexity: ${complexity}`, width));
		}

		if (dependsOn && dependsOn.length > 0) {
			lines.push(truncate(`    Depends: ${dependsOn.join(", ")}`, width));
		}

		return lines;
	}
}

function truncate(s: string, maxLen: number): string {
	if (s.length <= maxLen) return s;
	return s.slice(0, maxLen - 1) + "…";
}

import type { PlanTask } from "../extension/tool-registry.ts";

export interface DependencyEdge {
	from: string;
	to: string;
}

/** Text-based dependency visualization for plan tasks. */
export class DependencyGraph {
	constructor(private tasks: PlanTask[]) {}

	setTasks(tasks: PlanTask[]): void {
		this.tasks = tasks;
	}

	/** Render a text-based dependency graph. Returns lines for embedding. */
	render(width: number): string[] {
		if (this.tasks.length === 0) return ["(no tasks)"];

		const edges = this.buildEdges();
		if (edges.length === 0) {
			return this.tasks.map((t) => t.id);
		}

		// Find roots (tasks with no dependencies)
		const hasDep = new Set(edges.map((e) => e.to));
		const roots = this.tasks.filter((t) => !hasDep.has(t.id));

		// BFS to build layers
		const visited = new Set<string>();
		const layers: string[][] = [];
		let queue = roots.map((r) => r.id);

		while (queue.length > 0) {
			layers.push([...queue]);
			for (const id of queue) visited.add(id);
			const next: string[] = [];
			for (const id of queue) {
				for (const edge of edges) {
					if (edge.from === id && !visited.has(edge.to)) {
						next.push(edge.to);
					}
				}
			}
			queue = [...new Set(next)];
		}

		// Add unvisited tasks
		for (const t of this.tasks) {
			if (!visited.has(t.id)) {
				layers.push([t.id]);
			}
		}

		// Render layers as arrows
		const lines: string[] = [];
		for (let i = 0; i < layers.length; i++) {
			const layerStr = layers[i].join("  ");
			lines.push(truncate(layerStr, width));
			if (i < layers.length - 1) {
				const connector = layers[i].map(() => "↓").join("  ");
				lines.push(truncate(`  ${connector}`, width));
			}
		}

		return lines;
	}

	/** Identify the critical path (longest dependency chain). */
	getCriticalPath(): string[] {
		const taskMap = new Map(this.tasks.map((t) => [t.id, t]));
		const memo = new Map<string, string[]>();

		const longestFrom = (id: string): string[] => {
			if (memo.has(id)) return memo.get(id)!;
			const deps = this.tasks.filter((t) => t.dependsOn?.includes(id));
			if (deps.length === 0) {
				memo.set(id, [id]);
				return [id];
			}
			let best: string[] = [];
			for (const dep of deps) {
				const path = longestFrom(dep.id);
				if (path.length > best.length) best = path;
			}
			const result = [id, ...best];
			memo.set(id, result);
			return result;
		};

		// Start from roots
		const hasDep = new Set<string>();
		for (const t of this.tasks) {
			if (t.dependsOn) {
				for (const d of t.dependsOn) hasDep.add(d);
			}
		}
		const roots = this.tasks.filter((t) => !t.dependsOn || t.dependsOn.length === 0);

		let bestPath: string[] = [];
		for (const root of roots) {
			const path = longestFrom(root.id);
			if (path.length > bestPath.length) bestPath = path;
		}

		return bestPath;
	}

	/** Identify parallel groups (tasks that can run concurrently). */
	getParallelGroups(): string[][] {
		const completed = new Set<string>();
		const groups: string[][] = [];
		const remaining = new Set(this.tasks.map((t) => t.id));
		const taskMap = new Map(this.tasks.map((t) => [t.id, t]));

		while (remaining.size > 0) {
			const ready: string[] = [];
			for (const id of remaining) {
				const task = taskMap.get(id)!;
				const deps = task.dependsOn ?? [];
				if (deps.every((d) => completed.has(d))) {
					ready.push(id);
				}
			}
			if (ready.length === 0) break; // avoid infinite loop on circular deps
			groups.push(ready);
			for (const id of ready) {
				completed.add(id);
				remaining.delete(id);
			}
		}

		return groups;
	}

	private buildEdges(): DependencyEdge[] {
		const edges: DependencyEdge[] = [];
		for (const task of this.tasks) {
			if (task.dependsOn) {
				for (const depId of task.dependsOn) {
					edges.push({ from: depId, to: task.id });
				}
			}
		}
		return edges;
	}
}

function truncate(s: string, maxLen: number): string {
	if (s.length <= maxLen) return s;
	return s.slice(0, maxLen - 1) + "…";
}

/** Plan action types for the plan review overlay. */
export type PlanAction =
	| { type: "approve-all" }
	| { type: "reject"; reason: string }
	| { type: "edit-task"; taskId: string; updates: Record<string, unknown> }
	| { type: "deepen"; taskId?: string }
	| { type: "reorder"; taskIds: string[] };

export interface PlanActionResult {
	action: PlanAction;
	success: boolean;
	message: string;
}

/** Handle plan actions. Returns a result describing what happened. */
export function executePlanAction(action: PlanAction, taskCount: number): PlanActionResult {
	switch (action.type) {
		case "approve-all":
			return {
				action,
				success: true,
				message: `Approved all ${taskCount} tasks`,
			};

		case "reject":
			if (!action.reason || action.reason.trim() === "") {
				return {
					action,
					success: false,
					message: "Rejection requires a reason",
				};
			}
			return {
				action,
				success: true,
				message: `Plan rejected: ${action.reason}`,
			};

		case "edit-task": {
			if (!action.taskId) {
				return { action, success: false, message: "Missing taskId" };
			}
			return {
				action,
				success: true,
				message: `Task ${action.taskId} updated`,
			};
		}

		case "deepen":
			return {
				action,
				success: true,
				message: action.taskId
					? `Deepening plan for task ${action.taskId}`
					: "Deepening entire plan",
			};

		case "reorder": {
			if (action.taskIds.length !== taskCount) {
				return {
					action,
					success: false,
					message: `Expected ${taskCount} task IDs, got ${action.taskIds.length}`,
				};
			}
			return {
				action,
				success: true,
				message: "Tasks reordered",
			};
		}
	}
}

/** Keyboard shortcut mapping for plan actions. */
export function parsePlanKey(key: string): PlanAction | null {
	switch (key) {
		case "a": return { type: "approve-all" };
		case "d": return { type: "deepen" };
		default: return null;
	}
}

import type { Component } from "../components/scrollable.ts";
import type { VisualState, PlanTask } from "../extension/tool-registry.ts";
import { TaskCard } from "./task-card.ts";
import { DependencyGraph } from "./dependency-graph.ts";
import { executePlanAction, parsePlanKey, type PlanAction } from "./plan-actions.ts";

/** Plan Review Overlay — interactive plan visualization. */
export class PlanOverlay implements Component {
	private selectedIndex = 0;
	private expanded = false;
	private lastAction: string | null = null;

	constructor(private state: VisualState) {}

	getSelectedIndex(): number {
		return this.selectedIndex;
	}

	isExpanded(): boolean {
		return this.expanded;
	}

	toggleExpand(): void {
		this.expanded = !this.expanded;
	}

	render(width: number): string[] {
		const { plan } = this.state;
		if (!plan) {
			return boxLines(width, [
				"Plan Review: No plan loaded",
				"",
				"Use /visual plan or visual_update_plan tool to push a plan.",
			]);
		}

		const lines: string[] = [];

		// Header
		lines.push(`Plan Review: ${plan.title}`);
		lines.push(`Status: ${plan.status}${plan.status === "READY" ? " — awaiting approval" : ""}`);
		lines.push("");

		// Task cards
		for (let i = 0; i < plan.tasks.length; i++) {
			const task = plan.tasks[i];
			const card = new TaskCard(task);
			const cardLines = card.render(width - 4);

			if (i === this.selectedIndex) {
				// Highlight selected task
				for (const line of cardLines) {
					lines.push(`▸ ${line}`);
				}
			} else {
				for (const line of cardLines) {
					lines.push(`  ${line}`);
				}
			}
			lines.push("");
		}

		// Dependency graph summary
		if (plan.tasks.length > 1) {
			const graph = new DependencyGraph(plan.tasks);
			const critPath = graph.getCriticalPath();
			lines.push(`Critical path: ${critPath.join(" → ")}`);

			const groups = graph.getParallelGroups();
			if (groups.length > 1) {
				lines.push(`Parallel groups: ${groups.length}`);
			}
			lines.push("");
		}

		// Last action feedback
		if (this.lastAction) {
			lines.push(`Last: ${this.lastAction}`);
			lines.push("");
		}

		// Footer
		lines.push("[Enter] View details  [a] Approve all  [r] Reject");
		lines.push("[↑↓] Navigate  [e] Edit task  [d] Deepen plan  [q] Close");

		return boxLines(width, lines);
	}

	handleInput(data: string): void {
		const plan = this.state.plan;
		if (!plan) return;

		switch (data) {
			case "\x1b[A": // Up
			case "k":
				if (this.selectedIndex > 0) this.selectedIndex--;
				break;
			case "\x1b[B": // Down
			case "j":
				if (this.selectedIndex < plan.tasks.length - 1) this.selectedIndex++;
				break;
			case "\r": // Enter
				this.expanded = !this.expanded;
				break;
			case "q":
				this.expanded = false;
				break;
			default: {
				const action = parsePlanKey(data);
				if (action) {
					const result = executePlanAction(action, plan.tasks.length);
					this.lastAction = result.message;
				}
				break;
			}
		}
	}
}

/** Wrap lines in a box drawing. */
function boxLines(width: number, lines: string[]): string[] {
	const innerWidth = width - 4;
	const result: string[] = [];

	result.push(`┌${"─".repeat(innerWidth)}┐`);

	for (const line of lines) {
		const padded = line.length > innerWidth
			? line.slice(0, innerWidth)
			: line.padEnd(innerWidth);
		result.push(`│ ${padded} │`);
	}

	result.push(`└${"─".repeat(innerWidth)}┘`);
	return result;
}

import type { Component } from "../components/scrollable.ts";

export interface DiffLine {
	type: "context" | "add" | "remove" | "header";
	content: string;
	lineNumberOld?: number;
	lineNumberNew?: number;
}

export interface DiffHunk {
	fileName: string;
	oldStart: number;
	newStart: number;
	lines: DiffLine[];
}

/** Side-by-side diff rendering engine. */
export class SideBySide implements Component {
	private hunks: DiffHunk[] = [];
	private scrollOffset = 0;

	setHunks(hunks: DiffHunk[]): void {
		this.hunks = hunks;
		this.scrollOffset = 0;
	}

	getHunks(): DiffHunk[] {
		return this.hunks;
	}

	render(width: number): string[] {
		if (this.hunks.length === 0) {
			return ["(no diff hunks)"];
		}

		const halfWidth = Math.floor((width - 1) / 2);
		const lines: string[] = [];

		for (const hunk of this.hunks) {
			// File header
			lines.push(truncate(`─── ${hunk.fileName} ───`, width));

			// Pair removals with additions
			const paired = pairLines(hunk.lines);
			for (const pair of paired) {
				const left = formatDiffLine(pair.left, halfWidth, true);
				const right = formatDiffLine(pair.right, halfWidth, false);
				lines.push(`${left}│${right}`);
			}
		}

		return lines.slice(this.scrollOffset);
	}

	handleInput(data: string): void {
		switch (data) {
			case "\x1b[B": // Down
			case "j":
				this.scrollOffset++;
				break;
			case "\x1b[A": // Up
			case "k":
				this.scrollOffset = Math.max(0, this.scrollOffset - 1);
				break;
		}
	}
}

interface LinePair {
	left: DiffLine;
	right: DiffLine | null;
}

/** Pair removal and add lines for side-by-side display. */
function pairLines(lines: DiffLine[]): LinePair[] {
	const pairs: LinePair[] = [];
	let i = 0;

	while (i < lines.length) {
		const line = lines[i];

		if (line.type === "remove") {
			// Collect consecutive removes
			const removes: DiffLine[] = [];
			while (i < lines.length && lines[i].type === "remove") {
				removes.push(lines[i]);
				i++;
			}
			// Collect consecutive adds
			const adds: DiffLine[] = [];
			while (i < lines.length && lines[i].type === "add") {
				adds.push(lines[i]);
				i++;
			}
			// Pair them up
			const maxLen = Math.max(removes.length, adds.length);
			for (let j = 0; j < maxLen; j++) {
				pairs.push({
					left: removes[j] ?? { type: "context", content: "" },
					right: adds[j] ?? null,
				});
			}
		} else if (line.type === "add") {
			pairs.push({ left: { type: "context", content: "" }, right: line });
			i++;
		} else {
			// Context line
			pairs.push({ left: line, right: null });
			i++;
		}
	}

	return pairs;
}

function formatDiffLine(line: DiffLine, width: number, isLeft: boolean): string {
	const prefix = line.type === "remove" ? "- " : line.type === "add" ? "+ " : "  ";
	const content = `${prefix}${line.content}`;
	const padded = content.padEnd(width);
	if (padded.length > width) {
		return padded.slice(0, width);
	}
	return padded;
}

function truncate(s: string, maxLen: number): string {
	if (s.length <= maxLen) return s;
	return s.slice(0, maxLen - 1) + "…";
}

/** Inline annotation/comment system for diff review. */

export interface Annotation {
	fileName: string;
	lineNumber: number;
	author: string;
	text: string;
	timestamp: number;
}

/** Manages annotations for diff review. */
export class AnnotationStore {
	private annotations: Map<string, Annotation[]> = new Map();

	/** Add an annotation. Key is "fileName:lineNumber". */
	add(annotation: Annotation): void {
		const key = annotationKey(annotation.fileName, annotation.lineNumber);
		const list = this.annotations.get(key) ?? [];
		list.push(annotation);
		this.annotations.set(key, list);
	}

	/** Get annotations for a specific file and line. */
	get(fileName: string, lineNumber: number): Annotation[] {
		return this.annotations.get(annotationKey(fileName, lineNumber)) ?? [];
	}

	/** Get all annotations for a file. */
	getForFile(fileName: string): Annotation[] {
		const result: Annotation[] = [];
		for (const [key, list] of this.annotations) {
			if (key.startsWith(`${fileName}:`)) {
				result.push(...list);
			}
		}
		return result.sort((a, b) => a.lineNumber - b.lineNumber);
	}

	/** Remove a specific annotation. */
	remove(fileName: string, lineNumber: number, index: number): boolean {
		const key = annotationKey(fileName, lineNumber);
		const list = this.annotations.get(key);
		if (!list || index >= list.length) return false;
		list.splice(index, 1);
		if (list.length === 0) {
			this.annotations.delete(key);
		}
		return true;
	}

	/** Get total annotation count. */
	count(): number {
		let total = 0;
		for (const list of this.annotations.values()) {
			total += list.length;
		}
		return total;
	}

	/** Render annotations for a file as comment lines. */
	renderForFile(fileName: string): string[] {
		const annotations = this.getForFile(fileName);
		return annotations.map((a) => `  💬 L${a.lineNumber} (${a.author}): ${a.text}`);
	}
}

function annotationKey(fileName: string, lineNumber: number): string {
	return `${fileName}:${lineNumber}`;
}

import type { Component } from "../components/scrollable.ts";
