export interface ReviewSummaryState {
	totalFiles: number;
	totalFindings: number;
	findingsBySeverity: Record<string, number>;
	approved: boolean;
	reviewerNotes: string;
}

/** Review summary component showing findings overview. */
export class ReviewSummary implements Component {
	constructor(private state: ReviewSummaryState) {}

	update(state: ReviewSummaryState): void {
		this.state = state;
	}

	static fromFindings(findings: FindingEntry[]): ReviewSummary {
		const bySeverity: Record<string, number> = { critical: 0, high: 0, medium: 0, low: 0 };
		const files = new Set<string>();
		for (const f of findings) {
			bySeverity[f.severity] = (bySeverity[f.severity] ?? 0) + 1;
			files.add(f.file);
		}

		return {
			totalFiles: files.size,
			totalFindings: findings.length,
			findingsBySeverity: bySeverity,
			approved: false,
			reviewerNotes: "",
		};
	}

	render(width: number): string[] {
		const { totalFiles, totalFindings, findingsBySeverity, approved, reviewerNotes } = this.state;

		const lines: string[] = [];
		lines.push(truncate("Review Summary", width));
		lines.push(truncate("─".repeat(40), width));
		lines.push(truncate(`Files reviewed: ${totalFiles}`, width));
		lines.push(truncate(`Total findings: ${totalFindings}`, width));
		lines.push("");

		for (const [sev, count] of Object.entries(findingsBySeverity)) {
			if (count > 0) {
				const marker = severityMarker(sev);
				lines.push(truncate(`  ${marker} ${sev}: ${count}`, width));
			}
		}

		lines.push("");
		lines.push(truncate(`Status: ${approved ? "✅ Approved" : "⏳ Pending review"}`, width));

		if (reviewerNotes) {
			lines.push("");
			lines.push(truncate(`Notes: ${reviewerNotes}`, width));
		}

		return lines;
	}
}

function severityMarker(severity: string): string {
	switch (severity) {
		case "critical": return "🔴";
		case "high": return "🟠";
		case "medium": return "🟡";
		case "low": return "🟢";
		default: return "⚪";
	}
}

function truncate(s: string, maxLen: number): string {
	if (s.length <= maxLen) return s;
	return s.slice(0, maxLen - 1) + "…";
}

import type { Component } from "../components/scrollable.ts";
import type { VisualState } from "../extension/tool-registry.ts";
