import { AnnotationStore } from "./annotation.ts";
import { ReviewSummary } from "./review-summary.ts";

/** Diff Review Overlay — side-by-side diff with annotations. */
export class DiffOverlay implements Component {
	private sideBySide: SideBySide;
	private annotations: AnnotationStore;
	private currentHunkIndex = 0;
	private mode: "diff" | "summary" = "diff";

	constructor(private state: VisualState) {
		this.sideBySide = new SideBySide();
		this.annotations = new AnnotationStore();
	}

	setHunks(hunks: DiffHunk[]): void {
		this.sideBySide.setHunks(hunks);
		this.currentHunkIndex = 0;
	}

	getAnnotations(): AnnotationStore {
		return this.annotations;
	}

	render(width: number): string[] {
		const lines: string[] = [];

		// Header
		lines.push("Diff Review");

		if (this.sideBySide.getHunks().length === 0 && this.state.findings.length === 0) {
			lines.push("");
			lines.push("No diff loaded. Use /visual diff or visual_show_findings tool.");
			return boxLines(width, lines);
		}

		if (this.mode === "summary") {
			// Show review summary
			const summary = ReviewSummary.fromFindings(this.state.findings);
			const summaryLines = summary.render(width - 4);
			lines.push("");
			for (const l of summaryLines) lines.push(l);
		} else {
			// Show side-by-side diff
			lines.push("─── Side-by-side diff ───");
			lines.push("");
			const diffLines = this.sideBySide.render(width - 4);
			for (const l of diffLines) lines.push(l);

			// Show annotations if any
			for (const hunk of this.sideBySide.getHunks()) {
				const fileAnnotations = this.annotations.renderForFile(hunk.fileName);
				if (fileAnnotations.length > 0) {
					lines.push("");
					for (const a of fileAnnotations) lines.push(a);
				}
			}
		}

		// Footer
		lines.push("");
		lines.push("[n] Next change  [p] Prev  [c] Comment  [a] Approve");
		lines.push("[j/k] Scroll  [s] Summary  [q] Close");

		return boxLines(width, lines);
	}

	handleInput(data: string): void {
		const hunks = this.sideBySide.getHunks();
		switch (data) {
			case "n":
				this.currentHunkIndex = Math.min(hunks.length - 1, this.currentHunkIndex + 1);
				break;
			case "p":
				this.currentHunkIndex = Math.max(0, this.currentHunkIndex - 1);
				break;
			case "s":
				this.mode = this.mode === "diff" ? "summary" : "diff";
				break;
			case "j":
			case "\x1b[B":
				this.sideBySide.handleInput(data);
				break;
			case "k":
			case "\x1b[A":
				this.sideBySide.handleInput(data);
				break;
		}
	}
}

/** Wrap lines in a box drawing. */
function boxLines(width: number, lines: string[]): string[] {
