import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { SelectableList, type SelectableItem } from "../../src/components/selectable-list.ts";

describe("SelectableList", () => {
	const items: SelectableItem[] = [
		{ label: "Task 1", description: "First" },
		{ label: "Task 2", description: "Second" },
		{ label: "Task 3", description: "Third" },
	];

	it("renders items with selection marker", () => {
		const list = new SelectableList(items);
		const lines = list.render(80);
		assert.equal(lines[0], " > Task 1");
		assert.equal(lines[1], "   Task 2");
		assert.equal(lines[2], "   Task 3");
	});

	it("moves selection down with j/down arrow", () => {
		const list = new SelectableList(items);
		list.render(80);
		list.handleInput("j");
		assert.equal(list.getSelectedIndex(), 1);
	});

	it("moves selection up with k/up arrow", () => {
		const list = new SelectableList(items);
		list.render(80);
		list.handleInput("j");
		list.handleInput("k");
		assert.equal(list.getSelectedIndex(), 0);
	});

	it("does not go below last item", () => {
		const list = new SelectableList(items);
		list.render(80);
		list.handleInput("j");
		list.handleInput("j");
		list.handleInput("j"); // Already at 2
		assert.equal(list.getSelectedIndex(), 2);
	});

	it("does not go above first item", () => {
		const list = new SelectableList(items);
		list.render(80);
		list.handleInput("k");
		assert.equal(list.getSelectedIndex(), 0);
	});

	it("fires onSelect on Enter", () => {
		let selected: SelectableItem | null = null;
		const list = new SelectableList(items, {
			onSelect: (item) => { selected = item; },
		});
		list.render(80);
		list.handleInput("\r");
		assert.ok(selected);
		assert.equal(selected!.label, "Task 1");
	});

	it("updates items and clamps selection", () => {
		const list = new SelectableList(items);
		list.render(80);
		list.handleInput("j");
		list.handleInput("j");
		assert.equal(list.getSelectedIndex(), 2);
		list.setItems([{ label: "Only one" }]);
		assert.equal(list.getSelectedIndex(), 0);
	});

	it("truncates long labels", () => {
		const longItems = [{ label: "A".repeat(100) }];
		const list = new SelectableList(longItems);
		const lines = list.render(40);
		assert.ok(lines[0].length <= 40);
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { SplitPane, type SplitDirection } from "../../src/components/split-pane.ts";
import type { Component } from "../../src/components/scrollable.ts";

function makeTextComponent(text: string): Component {
	return {
		render(_width: number): string[] {
			return [text];
		},
	};
}

function makeMultiLineComponent(lines: string[]): Component {
	return {
		render(_width: number): string[] {
			return lines;
		},
	};
}

describe("SplitPane", () => {
	it("renders side by side in horizontal mode", () => {
		const left = makeTextComponent("Hello");
		const right = makeTextComponent("World");
		const pane = new SplitPane(left, right, "horizontal", 0.5);

		const lines = pane.render(20);
		assert.equal(lines.length, 1);
		assert.ok(lines[0].includes("│"));
		assert.ok(lines[0].includes("Hello"));
		assert.ok(lines[0].includes("World"));
	});

	it("renders stacked in vertical mode", () => {
		const left = makeTextComponent("Top");
		const right = makeTextComponent("Bottom");
		const pane = new SplitPane(left, right, "vertical");

		const lines = pane.render(20);
		assert.ok(lines.length >= 3);
		assert.ok(lines[0].includes("Top"));
		assert.ok(lines[2].includes("Bottom"));
	});

	it("pads shorter side with spaces", () => {
		const left = makeMultiLineComponent(["a", "b"]);
		const right = makeMultiLineComponent(["x"]);
		const pane = new SplitPane(left, right, "horizontal", 0.5);

		const lines = pane.render(20);
		assert.equal(lines.length, 2); // Max of 2, 1
	});

	it("respects split ratio", () => {
		const left = makeTextComponent("L");
		const right = makeTextComponent("R");
		const pane = new SplitPane(left, right, "horizontal", 0.3);

		const lines = pane.render(20);
		assert.ok(lines[0].includes("│"));
		// Left side should be shorter (0.3 * ~19 = ~5 chars + padding)
		const dividerPos = lines[0].indexOf("│");
		assert.ok(dividerPos < 12, `Divider at ${dividerPos}, expected < 12`);
	});

	it("clamps split ratio to valid range", () => {
		const left = makeTextComponent("L");
		const right = makeTextComponent("R");
		const pane = new SplitPane(left, right, "horizontal", 0.5);
		pane.setSplitRatio(0.0); // Should clamp to 0.1
		pane.setSplitRatio(1.5); // Should clamp to 0.9

		const lines = pane.render(20);
		assert.ok(lines.length >= 1);
	});
});

