import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { DependencyGraph } from "../../src/plan/dependency-graph.ts";
import type { PlanTask } from "../../src/extension/tool-registry.ts";

describe("DependencyGraph", () => {
	it("renders empty tasks", () => {
		const graph = new DependencyGraph([]);
		const lines = graph.render(80);
		assert.deepEqual(lines, ["(no tasks)"]);
	});

	it("renders tasks with no dependencies as flat list", () => {
		const tasks: PlanTask[] = [
			{ id: "01", description: "A", files: [], status: "pending" },
			{ id: "02", description: "B", files: [], status: "pending" },
		];
		const graph = new DependencyGraph(tasks);
		const lines = graph.render(80);
		assert.ok(lines[0].includes("01"));
		assert.ok(lines[1].includes("02"));
	});

	it("renders dependency chain", () => {
		const tasks: PlanTask[] = [
			{ id: "01", description: "A", files: [], status: "pending" },
			{ id: "02", description: "B", files: [], dependsOn: ["01"], status: "pending" },
			{ id: "03", description: "C", files: [], dependsOn: ["02"], status: "pending" },
		];
		const graph = new DependencyGraph(tasks);
		const lines = graph.render(80);
		assert.ok(lines.length >= 3);
		assert.ok(lines.some((l) => l.includes("↓")));
	});

	it("computes critical path", () => {
		const tasks: PlanTask[] = [
			{ id: "01", description: "A", files: [], status: "pending" },
			{ id: "02", description: "B", files: [], dependsOn: ["01"], status: "pending" },
			{ id: "03", description: "C", files: [], dependsOn: ["02"], status: "pending" },
		];
		const graph = new DependencyGraph(tasks);
		const path = graph.getCriticalPath();
		assert.deepEqual(path, ["01", "02", "03"]);
	});

	it("computes parallel groups", () => {
		const tasks: PlanTask[] = [
			{ id: "01", description: "A", files: [], status: "pending" },
			{ id: "02", description: "B", files: [], status: "pending" },
			{ id: "03", description: "C", files: [], dependsOn: ["01", "02"], status: "pending" },
		];
		const graph = new DependencyGraph(tasks);
		const groups = graph.getParallelGroups();
		assert.equal(groups.length, 2);
		assert.deepEqual(groups[0], ["01", "02"]);
		assert.deepEqual(groups[1], ["03"]);
	});

	it("setTasks updates the graph", () => {
		const graph = new DependencyGraph([]);
		graph.setTasks([
			{ id: "01", description: "A", files: [], status: "pending" },
		]);
		const lines = graph.render(80);
		assert.ok(lines[0].includes("01"));
	});
});

