		const lines = sbs.render(80);
		assert.ok(lines.some((l) => l.includes("old line")));
		assert.ok(lines.some((l) => l.includes("new line")));
		assert.ok(lines.some((l) => l.includes("│")));
	});

	it("pairs unequal remove/add counts", () => {
		const sbs = new SideBySide();
		sbs.setHunks([{
			fileName: "test.ts",
			oldStart: 1,
			newStart: 1,
			lines: [
				{ type: "remove", content: "line 1" },
				{ type: "remove", content: "line 2" },
				{ type: "add", content: "line 3" },
			],
		}]);

		const lines = sbs.render(80);
		assert.ok(lines.length >= 3);
	});

	it("scrolls with j/k", () => {
		const sbs = new SideBySide();
		sbs.setHunks([{
			fileName: "test.ts",
			oldStart: 1,
			newStart: 1,
			lines: Array.from({ length: 20 }, (_, i) => ({
				type: "context" as const,
				content: `line ${i}`,
			})),
		}]);

		const before = sbs.render(80);
		sbs.handleInput("j");
		const after = sbs.render(80);
		// After scrolling, lines should be different
		assert.ok(after.length > 0);
	});

	it("resets scroll on setHunks", () => {
		const sbs = new SideBySide();
		sbs.handleInput("j");
		sbs.handleInput("j");
		sbs.setHunks([{
			fileName: "a.ts",
			oldStart: 1,
			newStart: 1,
			lines: [{ type: "context", content: "x" }],
		}]);
		// Should not be scrolled
		const lines = sbs.render(80);
		assert.ok(lines[0].includes("a.ts"));
	});

	it("getHunks returns current hunks", () => {
		const sbs = new SideBySide();
		const hunks: DiffHunk[] = [{
			fileName: "test.ts",
			oldStart: 1,
			newStart: 1,
			lines: [],
		}];
		sbs.setHunks(hunks);
		assert.equal(sbs.getHunks().length, 1);
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { AnnotationStore, type Annotation } from "../../src/diff/annotation.ts";

describe("AnnotationStore", () => {
	it("adds and retrieves annotations", () => {
		const store = new AnnotationStore();
		const annotation: Annotation = {
			fileName: "test.ts",
			lineNumber: 5,
			author: "reviewer",
			text: "This looks wrong",
			timestamp: Date.now(),
		};

		store.add(annotation);
		const result = store.get("test.ts", 5);
		assert.equal(result.length, 1);
		assert.equal(result[0].text, "This looks wrong");
	});

	it("returns empty array for non-existent key", () => {
		const store = new AnnotationStore();
		assert.deepEqual(store.get("missing.ts", 1), []);
	});

	it("supports multiple annotations per line", () => {
		const store = new AnnotationStore();
		store.add({ fileName: "a.ts", lineNumber: 1, author: "a", text: "first", timestamp: 1 });
		store.add({ fileName: "a.ts", lineNumber: 1, author: "b", text: "second", timestamp: 2 });

		const result = store.get("a.ts", 1);
		assert.equal(result.length, 2);
	});

	it("retrieves annotations for a file", () => {
		const store = new AnnotationStore();
		store.add({ fileName: "a.ts", lineNumber: 1, author: "x", text: "t1", timestamp: 1 });
		store.add({ fileName: "a.ts", lineNumber: 5, author: "x", text: "t2", timestamp: 2 });
		store.add({ fileName: "b.ts", lineNumber: 1, author: "x", text: "t3", timestamp: 3 });

		const result = store.getForFile("a.ts");
		assert.equal(result.length, 2);
		assert.equal(result[0].lineNumber, 1);
		assert.equal(result[1].lineNumber, 5);
	});

	it("removes annotation", () => {
		const store = new AnnotationStore();
		store.add({ fileName: "a.ts", lineNumber: 1, author: "x", text: "t1", timestamp: 1 });
		store.add({ fileName: "a.ts", lineNumber: 1, author: "x", text: "t2", timestamp: 2 });

		assert.equal(store.count(), 2);
		store.remove("a.ts", 1, 0);
		assert.equal(store.count(), 1);
	});

	it("returns false for invalid removal", () => {
		const store = new AnnotationStore();
		assert.equal(store.remove("missing.ts", 1, 0), false);
	});

	it("counts total annotations", () => {
		const store = new AnnotationStore();
		assert.equal(store.count(), 0);
		store.add({ fileName: "a.ts", lineNumber: 1, author: "x", text: "t", timestamp: 1 });
		assert.equal(store.count(), 1);
	});

	it("renders annotations for file", () => {
		const store = new AnnotationStore();
		store.add({ fileName: "a.ts", lineNumber: 5, author: "bot", text: "fix this", timestamp: 1 });

		const rendered = store.renderForFile("a.ts");
		assert.equal(rendered.length, 1);
		assert.ok(rendered[0].includes("fix this"));
		assert.ok(rendered[0].includes("L5"));
	});
});

