import { ImpactView, type ImpactStats } from "../../src/architecture/impact-view.ts";
import type { FileEntry } from "../../src/architecture/file-graph.ts";

describe("ImpactView", () => {
	it("returns null stats with no entries", () => {
		const view = new ImpactView();
		assert.equal(view.getStats(), null);
	});

	it("renders no impact data message", () => {
		const view = new ImpactView();
		const lines = view.render(80);
		assert.deepEqual(lines, ["(no impact data)"]);
	});

	it("calculates stats from entries", () => {
		const entries: FileEntry[] = [
			{ path: "a.ts", status: "modified" },
			{ path: "b.ts", status: "new" },
			{ path: "c.ts", status: "dependency" },
		];
		const view = new ImpactView(entries);
		const stats = view.getStats()!;
		assert.equal(stats.modified, 1);
		assert.equal(stats.new, 1);
		assert.equal(stats.dependencies, 1);
		assert.equal(stats.deleted, 0);
	});

