		const entries: FileEntry[] = [
			{ path: "a.ts", status: "deleted" },
		];
		const view = new ImpactView(entries);
		assert.equal(view.getStats()!.risk, "HIGH");
	});

	it("assesses risk as MEDIUM for multiple modifications", () => {
		const entries: FileEntry[] = [
			{ path: "a.ts", status: "modified" },
			{ path: "b.ts", status: "new" },
			{ path: "c.ts", status: "new" },
		];
		const view = new ImpactView(entries);
		assert.equal(view.getStats()!.risk, "MEDIUM");
	});

	it("assesses risk as LOW for single modification", () => {
		const entries: FileEntry[] = [
			{ path: "a.ts", status: "modified" },
		];
		const view = new ImpactView(entries);
		assert.equal(view.getStats()!.risk, "LOW");
	});

	it("renders impact analysis", () => {
		const entries: FileEntry[] = [
			{ path: "a.ts", status: "modified" },
			{ path: "b.ts", status: "new" },
		];
		const view = new ImpactView(entries);
		const lines = view.render(80);
