		assert.ok(joined.includes("Impact Analysis"));
		assert.ok(joined.includes("Modified: 1"));
		assert.ok(joined.includes("New: 1"));
		assert.ok(joined.includes("Risk:"));
	});

	it("recalculates on setEntries", () => {
		const view = new ImpactView([]);
		assert.equal(view.getStats(), null);
		view.setEntries([{ path: "x.ts", status: "modified" }]);
		assert.notEqual(view.getStats(), null);
	});
});

