import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { createVisualState, type VisualState } from "../../src/extension/tool-registry.ts";
import { PlanOverlay } from "../../src/plan/plan-overlay.ts";
import { DiffOverlay } from "../../src/diff/diff-overlay.ts";
import { ArchOverlay } from "../../src/architecture/arch-overlay.ts";
import { ProgressWidget } from "../../src/progress/progress-widget.ts";

/**
 * Integration tests verifying that all visual overlays work together
 * with the shared VisualState.
 */
describe("Integration: Visual commands", () => {
	it("plan overlay reads from shared state", () => {
		const state = createVisualState();
		state.plan = {
			title: "Integration Plan",
			status: "READY",
			tasks: [
				{ id: "01", description: "Setup", files: ["src/index.ts"], status: "done" },
				{ id: "02", description: "Implement", files: ["src/main.ts"], dependsOn: ["01"], status: "in-progress" },
			],
		};

		const overlay = new PlanOverlay(state);
		const lines = overlay.render(80);
		const joined = lines.join("\n");

		assert.ok(joined.includes("Integration Plan"));
		assert.ok(joined.includes("[✓]"));
		assert.ok(joined.includes("[→]"));
		assert.ok(joined.includes("Critical path"));
	});

	it("diff overlay shows findings from shared state", () => {
		const state = createVisualState();
		state.findings = [
			{ file: "a.ts", line: 10, severity: "high", message: "Security issue" },
			{ file: "b.ts", severity: "medium", message: "Style issue" },
		];

		const overlay = new DiffOverlay(state);
		overlay.setHunks([{
			fileName: "a.ts",
			oldStart: 1,
			newStart: 1,
			lines: [{ type: "context", content: "line" }],
		}]);
		overlay.handleInput("s"); // Switch to summary

		const lines = overlay.render(80);
		const joined = lines.join("\n");
		assert.ok(joined.includes("Review Summary"));
		assert.ok(joined.includes("Total findings: 2"));
	});

	it("architecture overlay reads plan files", () => {
		const state = createVisualState();
		state.plan = {
			title: "Build feature",
			status: "DRAFT",
			tasks: [
				{ id: "01", description: "Core", files: ["src/core.ts", "src/utils.ts"], status: "pending" },
				{ id: "02", description: "Tests", files: ["test/core.test.ts"], status: "pending" },
			],
		};

		const overlay = new ArchOverlay(state);
		const lines = overlay.render(80);
		const joined = lines.join("\n");
		assert.ok(joined.includes("Build feature"));
		assert.ok(joined.includes("core.ts"));
		assert.ok(joined.includes("utils.ts"));
		assert.ok(joined.includes("Impact radius"));
	});

	it("progress widget reads progress state", () => {
		const state = createVisualState();
		state.progress = {
			total: 10,
			completed: 7,
			currentTask: "integration-test",
			phase: "testing",
			cost: 0.42,
		};

		const widget = new ProgressWidget(state);
		const lines = widget.render(80);
		assert.equal(lines.length, 1);
		assert.ok(lines[0].includes("70%"));
		assert.ok(lines[0].includes("7/10"));
		assert.ok(lines[0].includes("$0.42"));
	});

	it("all overlays can coexist on same state", () => {
		const state = createVisualState();
		state.plan = {
			title: "Full test",
			status: "READY",
			tasks: [
				{ id: "01", description: "T1", files: ["a.ts"], status: "done" },
			],
		};
		state.progress = { total: 1, completed: 1, currentTask: "done", phase: "complete" };
		state.findings = [{ file: "a.ts", severity: "low", message: "nit" }];

		const plan = new PlanOverlay(state);
		const diff = new DiffOverlay(state);
		const arch = new ArchOverlay(state);
		const progress = new ProgressWidget(state);

		// All should render without errors
		assert.ok(plan.render(80).length > 0);
		assert.ok(diff.render(80).length > 0);
		assert.ok(arch.render(80).length > 0);
		assert.ok(progress.render(80).length > 0);
	});
});

