import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { ReviewSummary, ReviewSummaryState } from "../../src/diff/review-summary.ts";
import type { FindingEntry } from "../../src/extension/tool-registry.ts";

describe("ReviewSummary", () => {
	it("renders summary with no findings", () => {
		const summary = new ReviewSummary({
			totalFiles: 0,
			totalFindings: 0,
			findingsBySeverity: { critical: 0, high: 0, medium: 0, low: 0 },
			approved: false,
			reviewerNotes: "",
		});
		const lines = summary.render(80);
		assert.ok(lines.some((l) => l.includes("Total findings: 0")));
	});

	it("renders findings by severity", () => {
		const summary = new ReviewSummary({
			totalFiles: 2,
			totalFindings: 3,
			findingsBySeverity: { critical: 1, high: 1, medium: 1, low: 0 },
			approved: false,
			reviewerNotes: "",
		});
		const lines = summary.render(80);
		assert.ok(lines.some((l) => l.includes("critical: 1")));
		assert.ok(lines.some((l) => l.includes("high: 1")));
		assert.ok(lines.some((l) => l.includes("medium: 1")));
	});

	it("shows approved status", () => {
		const summary = new ReviewSummary({
			totalFiles: 1,
			totalFindings: 0,
			findingsBySeverity: { critical: 0, high: 0, medium: 0, low: 0 },
			approved: true,
			reviewerNotes: "",
		});
		const lines = summary.render(80);
		assert.ok(lines.some((l) => l.includes("Approved")));
	});

	it("shows pending status", () => {
		const summary = new ReviewSummary({
			totalFiles: 1,
			totalFindings: 0,
			findingsBySeverity: { critical: 0, high: 0, medium: 0, low: 0 },
			approved: false,
			reviewerNotes: "",
		});
		const lines = summary.render(80);
		assert.ok(lines.some((l) => l.includes("Pending")));
	});

	it("shows reviewer notes", () => {
		const summary = new ReviewSummary({
			totalFiles: 1,
			totalFindings: 1,
			findingsBySeverity: { critical: 0, high: 1, medium: 0, low: 0 },
			approved: false,
			reviewerNotes: "Looks good overall",
		});
		const lines = summary.render(80);
		assert.ok(lines.some((l) => l.includes("Looks good overall")));
	});

	it("fromFindings creates correct summary", () => {
		const findings: FindingEntry[] = [
			{ file: "a.ts", line: 10, severity: "high", message: "bug" },
			{ file: "a.ts", line: 20, severity: "medium", message: "style" },
			{ file: "b.ts", line: 5, severity: "critical", message: "vuln" },
		];
		const summary = ReviewSummary.fromFindings(findings);
		assert.equal(summary.totalFiles, 2);
		assert.equal(summary.totalFindings, 3);
		assert.equal(summary.findingsBySeverity.critical, 1);
		assert.equal(summary.findingsBySeverity.high, 1);
		assert.equal(summary.findingsBySeverity.medium, 1);
	});

	it("truncates long lines", () => {
		const summary = new ReviewSummary({
			totalFiles: 1,
			totalFindings: 1,
			findingsBySeverity: { critical: 0, high: 0, medium: 0, low: 0 },
			approved: false,
			reviewerNotes: "N".repeat(200),
		});
		const lines = summary.render(40);
		for (const line of lines) {
			assert.ok(line.length <= 40, `Line too long: ${line.length}`);
		}
	});
});

