/** TUI Component interface matching Pi's component model. */
export interface Component {
	render(width: number): string[];
	handleInput?(data: string): void;
	dispose?(): void;
}

/** Scrollable container that wraps a child component in a virtual-scroll viewport. */
export class Scrollable implements Component {
	private scrollOffset = 0;
	private cachedLines: string[] = [];
	private child: Component;
	private maxHeight: number;

	constructor(child: Component, maxHeight: number = 20) {
		this.child = child;
		this.maxHeight = maxHeight;
	}

	getScrollOffset(): number {
		return this.scrollOffset;
	}

	setScrollOffset(offset: number): void {
		this.scrollOffset = Math.max(0, offset);
	}

	getMaxHeight(): number {
		return this.maxHeight;
	}

	setMaxHeight(h: number): void {
		this.maxHeight = h;
	}

	render(width: number): string[] {
		this.cachedLines = this.child.render(width);
		const visible = this.cachedLines.slice(this.scrollOffset, this.scrollOffset + this.maxHeight);

		// If not enough lines to fill viewport, scroll up
		if (visible.length < this.maxHeight && this.scrollOffset > 0) {
			this.scrollOffset = Math.max(0, this.cachedLines.length - this.maxHeight);
			return this.cachedLines.slice(this.scrollOffset, this.scrollOffset + this.maxHeight);
		}

		return visible;
	}

	handleInput(data: string): void {
		const total = this.cachedLines.length;
		switch (data) {
			case "\x1b[A": // Up arrow
			case "k":
				this.scrollOffset = Math.max(0, this.scrollOffset - 1);
				break;
			case "\x1b[B": // Down arrow
			case "j":
				this.scrollOffset = Math.min(Math.max(0, total - this.maxHeight), this.scrollOffset + 1);
				break;
			case "\x1b[5~": // Page Up
				this.scrollOffset = Math.max(0, this.scrollOffset - this.maxHeight);
				break;
			case "\x1b[6~": // Page Down
				this.scrollOffset = Math.min(Math.max(0, total - this.maxHeight), this.scrollOffset + this.maxHeight);
				break;
			case "g": // Home
				this.scrollOffset = 0;
				break;
			case "G": // End
				this.scrollOffset = Math.max(0, total - this.maxHeight);
				break;
		}
	}

	getTotalLines(): number {
		return this.cachedLines.length;
	}
}

import { Scrollable, type Component } from "./scrollable.ts";

export interface SelectableItem {
	label: string;
	description?: string;
	data?: unknown;
}

export class SelectableList implements Component {
	private scrollable: Scrollable;
	private selectedIndex = 0;
	private items: SelectableItem[];
	private onSelect?: (item: SelectableItem, index: number) => void;

	constructor(
		items: SelectableItem[],
		opts?: {
			maxHeight?: number;
			onSelect?: (item: SelectableItem, index: number) => void;
		},
	) {
		this.items = items;
		this.onSelect = opts?.onSelect;
		// Inner component for rendering raw list
		const self = this;
		const inner: Component = {
			render(width: number): string[] {
				return self.renderItems(width);
			},
		};
		this.scrollable = new Scrollable(inner, opts?.maxHeight ?? 15);
	}

	getSelectedIndex(): number {
		return this.selectedIndex;
	}

	setItems(items: SelectableItem[]): void {
		this.items = items;
		if (this.selectedIndex >= items.length) {
			this.selectedIndex = Math.max(0, items.length - 1);
		}
	}

	render(width: number): string[] {
		return this.scrollable.render(width);
	}

	handleInput(data: string): void {
		switch (data) {
			case "\x1b[A": // Up arrow
			case "k":
				if (this.selectedIndex > 0) {
					this.selectedIndex--;
					this.ensureVisible();
				}
				break;
			case "\x1b[B": // Down arrow
			case "j":
				if (this.selectedIndex < this.items.length - 1) {
					this.selectedIndex++;
					this.ensureVisible();
				}
				break;
			case "\r": // Enter
			case " ":
				if (this.onSelect && this.items[this.selectedIndex]) {
					this.onSelect(this.items[this.selectedIndex], this.selectedIndex);
				}
				break;
			default:
				this.scrollable.handleInput(data);
				break;
		}
	}

	private ensureVisible(): void {
		const offset = this.scrollable.getScrollOffset();
		const max = this.scrollable.getMaxHeight();
		if (this.selectedIndex < offset) {
			this.scrollable.setScrollOffset(this.selectedIndex);
		} else if (this.selectedIndex >= offset + max) {
			this.scrollable.setScrollOffset(this.selectedIndex - max + 1);
		}
	}

	private renderItems(width: number): string[] {
		return this.items.map((item, i) => {
			const marker = i === this.selectedIndex ? " > " : "   ";
			const label = item.label;
			const line = `${marker}${label}`;
			if (line.length > width) {
				return line.slice(0, width);
			}
			return line;
		});
	}
}

import type { Component } from "./scrollable.ts";

export type SplitDirection = "horizontal" | "vertical";

export class SplitPane implements Component {
	private left: Component;
	private right: Component;
	private direction: SplitDirection;
	private splitRatio: number;

	constructor(
		left: Component,
		right: Component,
		direction: SplitDirection = "horizontal",
		splitRatio: number = 0.5,
	) {
		this.left = left;
		this.right = right;
		this.direction = direction;
		this.splitRatio = splitRatio;
	}

	setSplitRatio(ratio: number): void {
		this.splitRatio = Math.max(0.1, Math.min(0.9, ratio));
	}

	render(width: number): string[] {
		if (this.direction === "horizontal") {
			return this.renderSideBySide(width);
		}
		return this.renderStacked(width);
	}

	handleInput(data: string): void {
		// Pass input to both children; the focused one should handle it
		this.left.handleInput?.(data);
		this.right.handleInput?.(data);
	}

	private renderSideBySide(width: number): string[] {
		const dividerWidth = 1;
		const leftWidth = Math.max(1, Math.floor((width - dividerWidth) * this.splitRatio));
		const rightWidth = Math.max(1, width - leftWidth - dividerWidth);

		const leftLines = this.left.render(leftWidth);
		const rightLines = this.right.render(rightWidth);

		const maxLines = Math.max(leftLines.length, rightLines.length);
		const result: string[] = [];

		for (let i = 0; i < maxLines; i++) {
			const left = (leftLines[i] ?? "").padEnd(leftWidth).slice(0, leftWidth);
			const right = (rightLines[i] ?? "").padEnd(rightWidth).slice(0, rightWidth);
			result.push(`${left}│${right}`);
		}

		return result;
	}

	private renderStacked(width: number): string[] {
		const leftLines = this.left.render(width);
		const divider = "─".repeat(width);
		const rightLines = this.right.render(width);
		return [...leftLines, divider, ...rightLines];
	}
}

import type { Component } from "../components/scrollable.ts";
import type { ProgressState } from "../extension/tool-registry.ts";

/** Single-line progress bar component. */
export class StatusLine implements Component {
	private state: ProgressState;

	constructor(state: ProgressState) {
		this.state = state;
	}

	update(state: ProgressState): void {
		this.state = state;
	}

	render(width: number): string[] {
		const { total, completed, currentTask, phase, cost } = this.state;

		const pct = total > 0 ? completed / total : 0;
		const barWidth = 20;
		const filled = Math.round(barWidth * pct);
		const empty = barWidth - filled;
		const bar = "█".repeat(filled) + "░".repeat(empty);
		const pctStr = `${Math.round(pct * 100)}%`;

		let line = `📊 Pipeline: [${bar}] ${pctStr} — ${completed}/${total} (${phase}: ${currentTask})`;
		if (cost !== undefined) {
			line += ` | Cost: $${cost.toFixed(2)}`;
		}

		if (line.length > width) {
			line = line.slice(0, width);
		}

		return [line];
	}
}

import type { Component } from "../components/scrollable.ts";
import type { VisualState } from "../extension/tool-registry.ts";
import { StatusLine } from "./status-line.ts";

/** Task progress widget for powerbar/footer display. */
export class ProgressWidget implements Component {
	private visible = true;
	private statusLine: StatusLine | null = null;
	private state: VisualState;

	constructor(state: VisualState) {
		this.state = state;
		if (state.progress) {
			this.statusLine = new StatusLine(state.progress);
		}
	}

	isVisible(): boolean {
		return this.visible;
	}

	toggle(): void {
		this.visible = !this.visible;
	}

	render(width: number): string[] {
		if (!this.visible) return [];
		if (!this.state.progress) {
			return ["📊 Pipeline: No active pipeline"];
		}

		this.statusLine = new StatusLine(this.state.progress);
		return this.statusLine.render(width);
	}

	handleInput(_data: string): void {
		// Widget does not handle input
	}
}

import type { Component } from "../components/scrollable.ts";
import type { PlanTask } from "../extension/tool-registry.ts";

/** Renders a single task card within the plan review overlay. */
export class TaskCard implements Component {
	private task: PlanTask;

	constructor(task: PlanTask) {
		this.task = task;
	}

	getTask(): PlanTask {
		return this.task;
	}

	update(task: PlanTask): void {
		this.task = task;
	}

	render(width: number): string[] {
		const { id, description, files, complexity, dependsOn, status } = this.task;

		const check = status === "done" ? "[✓]" : status === "in-progress" ? "[→]" : "[ ]";
		const header = `${check} ${id}. ${description}`;

		const lines: string[] = [];
		lines.push(truncate(header, width));

		if (files.length > 0) {
			const filesStr = `    Files: ${files.join(", ")}`;
			lines.push(truncate(filesStr, width));
		}

		if (complexity) {
			lines.push(truncate(`    Complexity: ${complexity}`, width));
		}

		if (dependsOn && dependsOn.length > 0) {
			lines.push(truncate(`    Depends: ${dependsOn.join(", ")}`, width));
		}

		return lines;
	}
}

function truncate(s: string, maxLen: number): string {
	if (s.length <= maxLen) return s;
	return s.slice(0, maxLen - 1) + "…";
}

import type { PlanTask } from "../extension/tool-registry.ts";

export interface DependencyEdge {
	from: string;
	to: string;
}

/** Text-based dependency visualization for plan tasks. */
export class DependencyGraph {
	private tasks: PlanTask[];

	constructor(tasks: PlanTask[]) {
		this.tasks = tasks;
	}

	setTasks(tasks: PlanTask[]): void {
		this.tasks = tasks;
	}

	/** Render a text-based dependency graph. Returns lines for embedding. */
	render(width: number): string[] {
		if (this.tasks.length === 0) return ["(no tasks)"];

		const edges = this.buildEdges();
		if (edges.length === 0) {
			return this.tasks.map((t) => t.id);
		}

		// Find roots (tasks with no dependencies)
		const hasDep = new Set(edges.map((e) => e.to));
		const roots = this.tasks.filter((t) => !hasDep.has(t.id));

		// BFS to build layers
		const visited = new Set<string>();
		const layers: string[][] = [];
		let queue = roots.map((r) => r.id);

		while (queue.length > 0) {
			layers.push([...queue]);
			for (const id of queue) visited.add(id);
			const next: string[] = [];
			for (const id of queue) {
				for (const edge of edges) {
					if (edge.from === id && !visited.has(edge.to)) {
						next.push(edge.to);
					}
				}
			}
			queue = [...new Set(next)];
		}

		// Add unvisited tasks
		for (const t of this.tasks) {
			if (!visited.has(t.id)) {
				layers.push([t.id]);
			}
		}

		// Render layers as arrows
		const lines: string[] = [];
		for (let i = 0; i < layers.length; i++) {
			const layerStr = layers[i].join("  ");
			lines.push(truncate(layerStr, width));
			if (i < layers.length - 1) {
				const connector = layers[i].map(() => "↓").join("  ");
				lines.push(truncate(`  ${connector}`, width));
			}
		}

		return lines;
	}

	/** Identify the critical path (longest dependency chain). */
	getCriticalPath(): string[] {
		const memo = new Map<string, string[]>();

		const longestFrom = (id: string): string[] => {
			if (memo.has(id)) return memo.get(id)!;
			const deps = this.tasks.filter((t) => t.dependsOn?.includes(id));
			if (deps.length === 0) {
				memo.set(id, [id]);
				return [id];
			}
			let best: string[] = [];
			for (const dep of deps) {
				const path = longestFrom(dep.id);
				if (path.length > best.length) best = path;
			}
			const result = [id, ...best];
			memo.set(id, result);
			return result;
		};

		// Start from roots
		const roots = this.tasks.filter((t) => !t.dependsOn || t.dependsOn.length === 0);

		let bestPath: string[] = [];
		for (const root of roots) {
			const path = longestFrom(root.id);
			if (path.length > bestPath.length) bestPath = path;
		}

		return bestPath;
	}

	/** Identify parallel groups (tasks that can run concurrently). */
	getParallelGroups(): string[][] {
		const completed = new Set<string>();
		const groups: string[][] = [];
		const remaining = new Set(this.tasks.map((t) => t.id));
		const taskMap = new Map(this.tasks.map((t) => [t.id, t]));

		while (remaining.size > 0) {
			const ready: string[] = [];
			for (const id of remaining) {
				const task = taskMap.get(id)!;
				const deps = task.dependsOn ?? [];
				if (deps.every((d) => completed.has(d))) {
					ready.push(id);
				}
			}
			if (ready.length === 0) break; // avoid infinite loop on circular deps
			groups.push(ready);
			for (const id of ready) {
				completed.add(id);
				remaining.delete(id);
			}
		}

		return groups;
	}

	private buildEdges(): DependencyEdge[] {
		const edges: DependencyEdge[] = [];
		for (const task of this.tasks) {
			if (task.dependsOn) {
				for (const depId of task.dependsOn) {
					edges.push({ from: depId, to: task.id });
				}
			}
		}
		return edges;
	}
}

