import type { Component } from "../components/scrollable.ts";
import type { VisualState } from "../extension/tool-registry.ts";
import { TaskCard } from "./task-card.ts";
import { DependencyGraph } from "./dependency-graph.ts";
import { executePlanAction, parsePlanKey } from "./plan-actions.ts";

/** Plan Review Overlay — interactive plan visualization. */
export class PlanOverlay implements Component {
	private selectedIndex = 0;
	private expanded = false;
	private lastAction: string | null = null;
	private state: VisualState;

	constructor(state: VisualState) {
		this.state = state;
	}

	getSelectedIndex(): number {
		return this.selectedIndex;
	}

	isExpanded(): boolean {
		return this.expanded;
	}

	toggleExpand(): void {
		this.expanded = !this.expanded;
	}

	render(width: number): string[] {
		const { plan } = this.state;
		if (!plan) {
			return boxLines(width, [
				"Plan Review: No plan loaded",
				"",
				"Use /visual plan or visual_update_plan tool to push a plan.",
			]);
		}

		const lines: string[] = [];

		// Header
		lines.push(`Plan Review: ${plan.title}`);
		lines.push(`Status: ${plan.status}${plan.status === "READY" ? " — awaiting approval" : ""}`);
		lines.push("");

		// Task cards
		for (let i = 0; i < plan.tasks.length; i++) {
			const task = plan.tasks[i];
			const card = new TaskCard(task);
			const cardLines = card.render(width - 4);

			if (i === this.selectedIndex) {
				for (const line of cardLines) {
					lines.push(`▸ ${line}`);
				}
			} else {
				for (const line of cardLines) {
					lines.push(`  ${line}`);
				}
			}
			lines.push("");
		}

		// Dependency graph summary
		if (plan.tasks.length > 1) {
			const graph = new DependencyGraph(plan.tasks);
			const critPath = graph.getCriticalPath();
			lines.push(`Critical path: ${critPath.join(" → ")}`);

			const groups = graph.getParallelGroups();
			if (groups.length > 1) {
				lines.push(`Parallel groups: ${groups.length}`);
			}
			lines.push("");
		}

		// Last action feedback
		if (this.lastAction) {
			lines.push(`Last: ${this.lastAction}`);
			lines.push("");
		}

		// Footer
		lines.push("[Enter] View details  [a] Approve all  [r] Reject");
		lines.push("[↑↓] Navigate  [e] Edit task  [d] Deepen plan  [q] Close");

		return boxLines(width, lines);
	}

	handleInput(data: string): void {
		const plan = this.state.plan;
		if (!plan) return;

		switch (data) {
			case "\x1b[A": // Up
			case "k":
				if (this.selectedIndex > 0) this.selectedIndex--;
				break;
			case "\x1b[B": // Down
			case "j":
				if (this.selectedIndex < plan.tasks.length - 1) this.selectedIndex++;
				break;
			case "\r": // Enter
				this.expanded = !this.expanded;
				break;
			case "q":
				this.expanded = false;
				break;
			default: {
				const action = parsePlanKey(data);
				if (action) {
					const result = executePlanAction(action, plan.tasks.length);
					this.lastAction = result.message;
				}
				break;
			}
		}
	}
}

/** Wrap lines in a box drawing. */
function boxLines(width: number, lines: string[]): string[] {
	const innerWidth = width - 4;
	const result: string[] = [];

	result.push(`┌${"─".repeat(innerWidth)}┐`);

	for (const line of lines) {
		const padded = line.length > innerWidth
			? line.slice(0, innerWidth)
			: line.padEnd(innerWidth);
		result.push(`│ ${padded} │`);
	}

	result.push(`└${"─".repeat(innerWidth)}┘`);
	return result;
}

import type { Component } from "../components/scrollable.ts";
import type { VisualState } from "../extension/tool-registry.ts";
import { SideBySide, type DiffHunk } from "./side-by-side.ts";
import { AnnotationStore } from "./annotation.ts";
import { ReviewSummary, ReviewSummaryState } from "./review-summary.ts";

/** Diff Review Overlay — side-by-side diff with annotations. */
export class DiffOverlay implements Component {
	private sideBySide: SideBySide;
	private annotations: AnnotationStore;
	private currentHunkIndex = 0;
	private mode: "diff" | "summary" = "diff";
	private state: VisualState;

	constructor(state: VisualState) {
		this.state = state;
		this.sideBySide = new SideBySide();
		this.annotations = new AnnotationStore();
	}

	setHunks(hunks: DiffHunk[]): void {
		this.sideBySide.setHunks(hunks);
		this.currentHunkIndex = 0;
	}

	getAnnotations(): AnnotationStore {
		return this.annotations;
	}

	render(width: number): string[] {
		const lines: string[] = [];

		// Header
		lines.push("Diff Review");

		if (this.sideBySide.getHunks().length === 0 && this.state.findings.length === 0) {
			lines.push("");
			lines.push("No diff loaded. Use /visual diff or visual_show_findings tool.");
			return boxLines(width, lines);
		}

		if (this.mode === "summary") {
			// Show review summary
			const summaryState = ReviewSummary.fromFindings(this.state.findings);
			const summary = new ReviewSummary(summaryState);
			const summaryLines = summary.render(width - 4);
			lines.push("");
			for (const l of summaryLines) lines.push(l);
		} else {
			// Show side-by-side diff
			lines.push("─── Side-by-side diff ───");
			lines.push("");
			const diffLines = this.sideBySide.render(width - 4);
			for (const l of diffLines) lines.push(l);

			// Show annotations if any
			for (const hunk of this.sideBySide.getHunks()) {
				const fileAnnotations = this.annotations.renderForFile(hunk.fileName);
				if (fileAnnotations.length > 0) {
					lines.push("");
					for (const a of fileAnnotations) lines.push(a);
				}
			}
		}

		// Footer
		lines.push("");
		lines.push("[n] Next change  [p] Prev  [c] Comment  [a] Approve");
		lines.push("[j/k] Scroll  [s] Summary  [q] Close");

		return boxLines(width, lines);
	}

	handleInput(data: string): void {
		const hunks = this.sideBySide.getHunks();
		switch (data) {
			case "n":
				this.currentHunkIndex = Math.min(hunks.length - 1, this.currentHunkIndex + 1);
				break;
			case "p":
				this.currentHunkIndex = Math.max(0, this.currentHunkIndex - 1);
				break;
			case "s":
				this.mode = this.mode === "diff" ? "summary" : "diff";
				break;
			case "j":
			case "\x1b[B":
				this.sideBySide.handleInput(data);
				break;
			case "k":
			case "\x1b[A":
				this.sideBySide.handleInput(data);
				break;
		}
	}
}

