import type { Component } from "../components/scrollable.ts";
import type { FileEntry } from "./file-graph.ts";

export interface ImpactStats {
	modified: number;
	new: number;
	deleted: number;
	dependencies: number;
	risk: "LOW" | "MEDIUM" | "HIGH";
	riskReason: string;
}

/** Change impact visualization component. */
export class ImpactView implements Component {
	private stats: ImpactStats | null = null;
	private entries: FileEntry[];

	constructor(entries: FileEntry[] = []) {
		this.entries = entries;
		this.recalculate();
	}

	setEntries(entries: FileEntry[]): void {
		this.entries = entries;
		this.recalculate();
	}

	getStats(): ImpactStats | null {
		return this.stats;
	}

	private recalculate(): void {
		if (this.entries.length === 0) {
			this.stats = null;
			return;
		}

		let modified = 0;
		let newCount = 0;
		let deleted = 0;
		let dependencies = 0;

		for (const entry of this.entries) {
			switch (entry.status) {
				case "modified": modified++; break;
				case "new": newCount++; break;
				case "deleted": deleted++; break;
				case "dependency": dependencies++; break;
			}
		}

		// Risk assessment based on changes
		let risk: ImpactStats["risk"] = "LOW";
		let riskReason = "Minimal impact";

		if (deleted > 0) {
			risk = "HIGH";
			riskReason = "File deletions detected";
		} else if (modified > 3) {
			risk = "HIGH";
			riskReason = "Many files modified";
		} else if (modified > 1 || newCount > 2) {
			risk = "MEDIUM";
			riskReason = "Multiple files affected";
		} else if (modified > 0) {
			risk = "LOW";
			riskReason = "Limited changes";
		}

		this.stats = { modified, new: newCount, deleted, dependencies, risk, riskReason };
	}

	render(width: number): string[] {
		if (!this.stats) return ["(no impact data)"];

		const s = this.stats;
		const lines: string[] = [];

		lines.push(truncate("Impact Analysis", width));
		lines.push(truncate("─".repeat(30), width));
		lines.push(truncate(`Modified: ${s.modified}  New: ${s.new}  Deleted: ${s.deleted}  Dependencies: ${s.dependencies}`, width));
		lines.push("");

		const riskIcon = s.risk === "HIGH" ? "🔴" : s.risk === "MEDIUM" ? "🟡" : "🟢";
		lines.push(truncate(`Risk: ${riskIcon} ${s.risk} — ${s.riskReason}`, width));

		return lines;
	}
}

function truncate(s: string, maxLen: number): string {
	if (s.length <= maxLen) return s;
	return s.slice(0, maxLen - 1) + "…";
}

import type { Component } from "../components/scrollable.ts";
import type { VisualState } from "../extension/tool-registry.ts";
import { FileGraph, type FileEntry } from "./file-graph.ts";
import { ImpactView } from "./impact-view.ts";
import { SymbolMap } from "./symbol-map.ts";

/** Architecture View Overlay — file dependency graph and impact visualization. */
export class ArchOverlay implements Component {
	private fileGraph: FileGraph;
	private impactView: ImpactView;
	private symbolMap: SymbolMap;
	private mode: "tree" | "impact" | "symbols" = "tree";
	private state: VisualState;

	constructor(state: VisualState) {
		this.state = state;
		this.fileGraph = new FileGraph();
		this.impactView = new ImpactView();
		this.symbolMap = new SymbolMap();

		// Populate from plan state if available
		this.populateFromState();
	}

	setFileEntries(entries: FileEntry[]): void {
		this.fileGraph.setEntries(entries);
		this.impactView.setEntries(entries);
	}

	private populateFromState(): void {
		if (!this.state.plan) return;

		const entries: FileEntry[] = [];
		for (const task of this.state.plan.tasks) {
			for (const file of task.files) {
				entries.push({
					path: file,
					status: task.status === "done" ? "unchanged" : "modified",
				});
			}
		}
		// Deduplicate
		const seen = new Set<string>();
		const unique = entries.filter((e) => {
			if (seen.has(e.path)) return false;
			seen.add(e.path);
			return true;
		});
		this.fileGraph.setEntries(unique);
		this.impactView.setEntries(unique);
	}

	render(width: number): string[] {
		const lines: string[] = [];

		// Header
		const title = this.state.plan
			? `Architecture Impact: ${this.state.plan.title}`
			: "Architecture View";
		lines.push(title);
		lines.push("─".repeat(Math.min(width - 4, 60)));
		lines.push("");

		if (this.mode === "tree") {
			const treeLines = this.fileGraph.render(width - 4);
			for (const l of treeLines) lines.push(l);
		} else if (this.mode === "impact") {
			const impactLines = this.impactView.render(width - 4);
			for (const l of impactLines) lines.push(l);
		} else if (this.mode === "symbols") {
			for (const file of this.symbolMap.getAllFiles()) {
				const syms = this.symbolMap.renderForFile(file, width - 4);
				if (syms.length > 0) {
					lines.push(file);
					for (const s of syms) lines.push(`  ${s}`);
					lines.push("");
				}
			}
			if (this.symbolMap.getAllFiles().length === 0) {
				lines.push("(no symbol data — pi-lsp integration needed)");
			}
		}

		// Impact stats
		const stats = this.impactView.getStats();
		if (stats) {
			lines.push("");
			lines.push(`Impact radius: ${stats.modified} modified, ${stats.new} new, ${stats.dependencies} dependencies`);
			lines.push(`Risk: ${stats.risk} (${stats.riskReason})`);
		}

		// Footer
		lines.push("");
		lines.push("[Enter] View file  [d] Show dependencies  [t] Tree  [i] Impact  [q] Close");

		return boxLines(width, lines);
	}

	handleInput(data: string): void {
		switch (data) {
			case "t": this.mode = "tree"; break;
			case "i": this.mode = "impact"; break;
			case "s": this.mode = "symbols"; break;
		}
	}
}

/** Wrap lines in a box drawing. */
function boxLines(width: number, lines: string[]): string[] {
	const innerWidth = width - 4;
	const result: string[] = [];

	result.push(`┌${"─".repeat(innerWidth)}┐`);

	for (const line of lines) {
		const padded = line.length > innerWidth
			? line.slice(0, innerWidth)
			: line.padEnd(innerWidth);
		result.push(`│ ${padded} │`);
	}

	result.push(`└${"─".repeat(innerWidth)}┘`);
	return result;
}

